select distinct spst.id as rowId,spst.title as title,cuser.id as creator,cuser.name as creatorName,spst.create_time as createTime, cspabt.name as applyBookTypeName, cspt.name as projTypeName, spst.classCode as classCode,spst.first_unit_type as firstUnitType, csy.name as yearName, huser.name as headName,spst.header_audit_status as headerAuditStatus, spst.pre_audit_state as preAuditState, spst.audit_status as auditStatus, spst.project_apply_type,sdept.name as subDeptName, spst.is_ethic as isEthic,spst.phone as phone,spst.project_keyword as projectKeyword,spst.email as email, spst.sub_date as subDate,spst.project_source_unit as projectSourceUnit,spst.planed_end_date as planedEndDate, spst.contacts as contacts,fdiscipline.name as disciplineName, spst.funds as funds,spst.research_field as researchField,spst.early_research_info as earlyResearchInfo, spst.note as note,spst.data_status as dataStatus,csrf.name as researchFieldName,suser.name as subUserName from srm_project_solicit spst left join ct_srm_project_apply_book_type cspabt on cspabt.code=spst.apply_book_type left join ct_srm_proj_type cspt on cspt.code=spst.proj_type left join ct_srm_year csy on csy.code=spst.year left join ct_srm_dept sdept on sdept.id=spst.sub_dept left join ct_srm_user huser on huser.id=spst.head left join ct_srm_user suser on suser.id=spst.sub_user_id left join ct_srm_user cuser on cuser.id=spst.creator left join ct_srm_discipline fdiscipline on fdiscipline.code=spst.discipline left join ct_srm_research_field csrf on csrf.code=spst.research_field where 1=1
and (spst.sub_user_id=#{projectSolicitDto.userId} or spst.creator=#{projectSolicitDto.userId} or spst.id in (SELECT soli_proj_id FROM srm_project_solicit_member WHERE member_id = #{projectSolicitDto.userId}) )
and spst.project_apply_info=#{projectSolicitDto.projectApplyInfo}
and spst.is_ethic=#{projectSolicitDto.isEthic}
and spst.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')
and spst.sub_date >= #{projectSolicitDto.startDate}
and spst.sub_date <= #{projectSolicitDto.endDate}
and spst.year=#{projectSolicitDto.year}
and spst.pre_audit_state!="2" and spst.pre_audit_state!="3"
and spst.pre_audit_state="2"
and spst.pre_audit_state="3"
and spst.header_audit_status!="2" and spst.header_audit_status!="3"
and spst.header_audit_status=#{projectSolicitDto.headerAuditStatus}
and spst.header_audit_status=#{projectSolicitDto.headerAuditStatus}
and spst.data_status = #{projectSolicitDto.dataStatus}
order by spst.id desc

select distinct spst.id as rowId,spst.title as title,cuser.id as creator,cuser.name as creatorName,spst.create_time as createTime, cspabt.name as applyBookTypeName, cspt.name as projTypeName, spst.classCode as classCode,spst.first_unit_type as firstUnitType, csy.name as yearName, huser.name as headName, spst.header_audit_status as headerAuditStatus, spst.pre_audit_state as preAuditState, spst.project_apply_type,sdept.name as subDeptName, spst.is_ethic as isEthic,spst.phone as phone,spst.project_keyword as projectKeyword,spst.email as email, spst.sub_date as subDate,spst.project_source_unit as projectSourceUnit,spst.planed_end_date as planedEndDate, spst.contacts as contacts,fdiscipline.name as disciplineName, spst.funds as funds,spst.research_field as researchField,spst.early_research_info as earlyResearchInfo, spst.note as note,spst.data_status as dataStatus,suser.name as subUserName,eafrec.id from srm_project_solicit spst left join ct_srm_project_apply_book_type cspabt on cspabt.code=spst.apply_book_type left join ct_srm_proj_type cspt on cspt.code=spst.proj_type left join ct_srm_year csy on csy.code=spst.year left join ct_srm_dept sdept on sdept.id=spst.sub_dept left join ct_srm_user huser on huser.id=spst.head left join ct_srm_user suser on suser.id=spst.sub_user_id left join ct_srm_user cuser on cuser.id=spst.creator left join ct_srm_discipline fdiscipline on fdiscipline.code=spst.discipline left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spst.sys_no and eafrec.check_rec_id=spst.id where eafrec.step_no>1 and ( (spst.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spst.sys_no=seafrec.sys_no and seafrec.check_rec_id=spst.id) and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%') and eafrec.check_datetime is not null) or (spst.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) )
and spst.header_audit_status="0"
and spst.header_audit_status="2"
and spst.header_audit_status="3"
and spst.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')
and spst.sub_date >= #{projectSolicitDto.startDate}
and spst.sub_date <= #{projectSolicitDto.endDate}
and spst.year=#{projectSolicitDto.year}
and spst.proj_type=#{projectSolicitDto.projType}
order by eafrec.id desc

select distinct spst.id as rowId,spst.title as title,cuser.id as creator,cuser.name as creatorName,spst.create_time as createTime, cspabt.name as applyBookTypeName, cspt.name as projTypeName, spst.classCode as classCode,spst.first_unit_type as firstUnitType, csy.name as yearName, huser.name as headName, spst.header_audit_status as headerAuditStatus, spst.pre_audit_state as preAuditState,spst.audit_status as auditStatus, spst.project_apply_type,sdept.name as subDeptName, spst.is_ethic as isEthic,spst.phone as phone,spst.project_keyword as projectKeyword,spst.email as email, spst.sub_date as subDate,spst.project_source_unit as projectSourceUnit,spst.planed_end_date as planedEndDate, spst.contacts as contacts,fdiscipline.name as disciplineName, spst.funds as funds,spst.research_field as researchField,spst.early_research_info as earlyResearchInfo, spst.note as note,spst.data_status as dataStatus,suser.name as subUserName from srm_project_solicit spst left join ct_srm_project_apply_book_type cspabt on cspabt.code=spst.apply_book_type left join ct_srm_proj_type cspt on cspt.code=spst.proj_type left join ct_srm_year csy on csy.code=spst.year left join ct_srm_dept sdept on sdept.id=spst.sub_dept left join ct_srm_user huser on huser.id=spst.head left join ct_srm_user suser on suser.id=spst.sub_user_id left join ct_srm_user cuser on cuser.id=spst.creator left join ct_srm_discipline fdiscipline on fdiscipline.code=spst.discipline left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spst.sys_no and eafrec.check_rec_id=spst.id where eafrec.step_no>1 and header_audit_status=2
and ( (spst.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spst.sys_no=seafrec.sys_no and seafrec.check_rec_id=spst.id) and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%') and eafrec.check_datetime is not null) or (spst.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) )
and spst.pre_audit_state=#{projectSolicitDto.preAuditState}
and spst.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')
and spst.sub_date >= #{projectSolicitDto.startDate}
and spst.sub_date <= #{projectSolicitDto.endDate}

select distinct spst.id as rowId,spst.title as title,cuser.id as creator,cuser.name as creatorName,spst.create_time as createTime, cspabt.name as applyBookTypeName, cspt.name as projTypeName, spst.classCode as classCode,spst.first_unit_type as firstUnitType, csy.name as yearName, huser.name as headName, spst.header_audit_status as headerAuditStatus, spst.pre_audit_state as preAuditState,spst.audit_status as auditStatus, spst.project_apply_type,sdept.name as subDeptName, spst.is_ethic as isEthic,spst.phone as phone,spst.project_keyword as projectKeyword,spst.email as email, spst.sub_date as subDate,spst.project_source_unit as projectSourceUnit,spst.planed_end_date as planedEndDate, spst.contacts as contacts,fdiscipline.name as disciplineName, spst.funds as funds,spst.research_field as researchField,spst.early_research_info as earlyResearchInfo, spst.note as note,spst.data_status as dataStatus,suser.name as subUserName from srm_project_solicit spst left join ct_srm_project_apply_book_type cspabt on cspabt.code=spst.apply_book_type left join ct_srm_proj_type cspt on cspt.code=spst.proj_type left join ct_srm_year csy on csy.code=spst.year left join ct_srm_dept sdept on sdept.id=spst.sub_dept left join ct_srm_user huser on huser.id=spst.head left join ct_srm_user suser on suser.id=spst.sub_user_id left join ct_srm_user cuser on cuser.id=spst.creator left join ct_srm_discipline fdiscipline on fdiscipline.code=spst.discipline left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spst.sys_no and eafrec.check_rec_id=spst.id where eafrec.step_no>1 and (header_audit_status=2 or pre_audit_state=3 or audit_status=3)
and ( (spst.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spst.sys_no=seafrec.sys_no and seafrec.check_rec_id=spst.id) and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%') and eafrec.check_datetime is not null) or (spst.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{projectSolicitDto.userId}, '|%')) )
and spst.pre_audit_state=#{projectSolicitDto.preAuditState}
and spst.audit_status=#{projectSolicitDto.auditStatus}
and spst.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')
and spst.sub_date >= #{projectSolicitDto.startDate}
and spst.sub_date <= #{projectSolicitDto.endDate}
and spst.is_ethic = #{projectSolicitDto.isEthic}
